#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <cuda_runtime.h>
#include <device_launch_parameters.h>

// Inline timer definitions from timer.h
#include <unistd.h>
#include <stdint.h>
#include <stdlib.h>

__inline__ uint64_t rdtsc() 
{
     uint32_t lo, hi;
     __asm__ __volatile__ ("rdtsc" : "=a" (lo), "=d" (hi));
     return (uint64_t)hi << 32 | lo;
}

unsigned long long start_cycles;
#define startCycle() (start_cycles = rdtsc())
#define stopCycle(cycles) (cycles = rdtsc()-start_cycles)

#include <sys/time.h>

struct timeval starttime;
struct timeval endtime;

#define startTime() \
{ \
  gettimeofday(&starttime, 0); \
}
#define stopTime(valusecs) \
{ \
  gettimeofday(&endtime, 0); \
  valusecs = (endtime.tv_sec-starttime.tv_sec)*1000000+endtime.tv_usec-starttime.tv_usec; \
}

// End of timer.h inline content

void run(int argc, char** argv);

#define pin_stats_reset()   startCycle()
#define pin_stats_pause(cycles)   stopCycle(cycles)
#define pin_stats_dump(cycles)    printf("timer: %Lu\n", cycles)

#define BENCH_PRINT

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9

#define MIN(a, b) ((a)<=(b) ? (a) : (b))

__global__ void pathfinder_step(int* src, int* dst, int* wall_row, int cols) {
    int n = blockIdx.x * blockDim.x + threadIdx.x;
    if (n >= cols) return;

    int min = src[n];
    if (n > 0) {
        int left = src[n-1];
        if (left < min) min = left;
    }
    if (n < cols-1) {
        int right = src[n+1];
        if (right < min) min = right;
    }
    dst[n] = wall_row[n] + min;
}

void
init(int argc, char** argv)
{
	if(argc==3){
		cols = atoi(argv[1]);
		rows = atoi(argv[2]);
	}else{
                printf("Usage: pathfiner width num_of_steps\n");
                exit(0);
        }
	data = new int[rows*cols];
	wall = new int*[rows];
	for(int n=0; n<rows; n++)
		wall[n]=data+cols*n;
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
    for (int j = 0; j < cols; j++)
        result[j] = wall[0][j];
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ",wall[i][j]) ;
        }
        printf("\n") ;
    }
#endif
}

void 
fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);

}

int main(int argc, char** argv)
{
    run(argc,argv);

    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    unsigned long long cycles;

    int *src_host, *dst_host, *temp_host;
    int *src_dev, *dst_dev, *wall_dev;
    int min;

    dst_host = result;
    src_host = new int[cols];

    // Allocate device memory
    cudaMalloc(&src_dev, cols * sizeof(int));
    cudaMalloc(&dst_dev, cols * sizeof(int));
    cudaMalloc(&wall_dev, cols * sizeof(int));

    // Initialize src_host with result (first row)
    for(int i=0; i<cols; i++) src_host[i] = dst_host[i];

    pin_stats_reset();

    int block_size = 256;
    int num_blocks = (cols + block_size - 1) / block_size;

    for (int t = 0; t < rows-1; t++) {
        // Swap host pointers
        temp_host = src_host;
        src_host = dst_host;
        dst_host = temp_host;

        // Copy current src to device
        cudaMemcpy(src_dev, src_host, cols * sizeof(int), cudaMemcpyHostToDevice);
        // Copy next wall row to device
        cudaMemcpy(wall_dev, wall[t+1], cols * sizeof(int), cudaMemcpyHostToDevice);

        // Launch kernel
        pathfinder_step<<<num_blocks, block_size>>>(src_dev, dst_dev, wall_dev, cols);

        // Copy result back to host dst
        cudaMemcpy(dst_host, dst_dev, cols * sizeof(int), cudaMemcpyDeviceToHost);
    }

    pin_stats_pause(cycles);
    pin_stats_dump(cycles);

#ifdef BENCH_PRINT

    for (int i = 0; i < cols; i++)

            printf("%d ",data[i]) ;

    printf("\n") ;

    for (int i = 0; i < cols; i++)

            printf("%d ",dst_host[i]) ;

    printf("\n") ;

#endif

    delete [] data;
    delete [] wall;
    delete [] dst_host;
    delete [] src_host;

    cudaFree(src_dev);
    cudaFree(dst_dev);
    cudaFree(wall_dev);
}
